// AUTO-GENERATED by scripts/generate-search-index.mjs — do not hand-edit.
// Run `node scripts/generate-search-index.mjs` after adding/renaming/removing a preset or tutorial.
export default [
  { id: "tutorial_uv_mapping", name: { zh: "座標與 Mapping 入門", en: "Coordinates & Mapping Basics" }, description: { zh: "用棋盤格紋理認識 UV 座標，學會用紋理座標（Texture Coordinate）跟映射（Mapping）節點控制貼圖怎麼貼、貼幾次、貼在哪裡。", en: "Use a checker pattern to understand UV coordinates, and learn to control how a texture wraps, tiles, and positions using Texture Coordinate and Mapping." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_xyz_split", name: { zh: "分離/合併 XYZ：只拉伸單一軸", en: "Separate/Combine XYZ: Stretch Just One Axis" }, description: { zh: "用分離 XYZ（Separate XYZ）把座標拆成三個獨立數值、只對其中一軸做運算，再用合併 XYZ（Combine XYZ）接回去——這是「只想調整某一個方向」時的標準做法。", en: "Use Separate XYZ to split a coordinate into three independent values, operate on just one axis, then rejoin with Combine XYZ — the standard pattern when you only want to adjust one direction." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_glass", name: { zh: "做出一個玻璃材質", en: "Make a Glass Material" }, description: { zh: "用玻璃 BSDF（Glass BSDF）節點做出一個清澈的玻璃球，認識粗糙度（Roughness）與 IOR 這兩個關鍵參數。", en: "Use the Glass BSDF node to create a clear glass sphere, learning the Roughness and IOR parameters along the way." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_bright_contrast", name: { zh: "亮度/對比度：手機修圖同款滑桿", en: "Brightness/Contrast: Your Phone's Photo Sliders" }, description: { zh: "亮度/對比度（Brightness/Contrast）節點跟手機相簿的「亮度/對比」滑桿是同一個概念——直接調整材質顏色的明暗與反差，不需要重新調色。", en: "The Brightness/Contrast node is the same concept as your phone photo app's brightness/contrast sliders — directly tweaking a material color's tone and range without redoing the whole palette." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_magic_texture", name: { zh: "迷幻紋理：抽象花紋產生器", en: "Magic Texture: Abstract Pattern Generator" }, description: { zh: "迷幻紋理（Magic Texture）沒有對應的真實世界材質，純粹是好玩的抽象花紋產生器，很適合拿來做特效或風格化的材質。", en: "Magic Texture has no real-world material equivalent — it's a fun generator for abstract, kaleidoscope-like patterns, great for effects or stylized materials." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_gradient_texture", name: { zh: "漸變紋理：最簡單的紋理節點", en: "Gradient Texture: The Simplest Texture Node" }, description: { zh: "漸變紋理（Gradient Texture）沒有任何複雜參數，就是沿著一個方向從黑到白平滑漸變——最適合拿來理解「紋理節點輸出的其實就是一個 0 到 1 的數值」這件事。", en: "Gradient Texture has no complex parameters — it's just a smooth black-to-white transition along a direction. The simplest way to understand that a texture node's output is really just a 0-to-1 value." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_neon_sign", name: { zh: "做出發光招牌效果", en: "Make a Glowing Sign Effect" }, description: { zh: "用波浪紋理（Wave Texture）產生的條紋圖案驅動發光（Emission）的發光強度，做出「有些地方亮、有些地方暗」的霓虹招牌效果，而不是整片均勻發光。", en: "Drive Emission's brightness with a Wave Texture pattern to create a neon sign that glows unevenly — bright in some areas, dark in others — instead of a flat uniform glow." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_wireframe_fx", name: { zh: "線框特效：科技感全息", en: "Wireframe FX: Tech Hologram Look" }, description: { zh: "用線框（Wireframe）節點抓出三角面的邊線，接到發光（Emission）做出電影裡常見的「發光線框」全息效果。", en: "Use the Wireframe node to pick out triangle edges, then feed it into Emission for the glowing-lines hologram look seen in movies." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_math_remap", name: { zh: "用 Math 節點縮小數值範圍", en: "Narrow a Range with Math Nodes" }, description: { zh: "雜訊紋理（Noise Texture）的輸出永遠是 0-1，但很多時候你只想要一個比較窄的範圍（例如 0.2-0.5）。這個教學帶你用兩個數學（Math）節點手動做出「乘＋加」的縮放平移，理解映射範圍（Map Range）背後其實在做的事。", en: "Noise Texture always outputs 0-1, but often you only want a narrower range (like 0.2-0.5). This tutorial walks through using two Math nodes to manually scale-and-offset — understanding what Map Range does under the hood." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_clamp_node", name: { zh: "夾值：防止數值跑出合理範圍", en: "Clamp: Keeping Values in Range" }, description: { zh: "很多插槽（例如 Roughness）只接受 0-1，但接上其他運算節點後很容易跑出這個範圍。夾值（Clamp）節點強制把數值鎖在你指定的最小/最大之間，避免材質忽然全黑或全白。", en: "Many sockets (like Roughness) only expect 0-1, but wiring in other math nodes can easily push values outside that range. Clamp forces a value to stay within your chosen min/max, preventing a material from suddenly going pure black or white." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_metal", name: { zh: "做出拉絲金屬", en: "Make Brushed Metal" }, description: { zh: "用雜訊紋理（Noise Texture）驅動粗糙度（Roughness），做出粗糙度有變化的金屬，比固定數值更真實。", en: "Drive Roughness with a Noise Texture to create metal with varying roughness — more realistic than a flat value." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_wood", name: { zh: "做出程序化木紋", en: "Make Procedural Wood Grain" }, description: { zh: "串接波浪紋理（Wave Texture）、顏色漸變（Color Ramp）跟原理化 BSDF（Principled BSDF），完全不用貼圖就做出木紋材質。", en: "Chain Wave Texture, Color Ramp, and Principled BSDF together to create wood grain without any image textures." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_hsv_shift", name: { zh: "色相偏移：一鍵換色", en: "Hue Shift: One-Click Recolor" }, description: { zh: "用色相/飽和度/明度（Hue Saturation Value）節點調整顏色，比直接改 RGB 更直覺——轉 Hue 就能把紅色變藍色，不用重新調三個色版。", en: "Use the Hue Saturation Value node to adjust color — more intuitive than editing RGB directly. Turning Hue alone can flip red to blue without retuning three channels." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_invert_color", name: { zh: "反色：快速做出互補色遮罩", en: "Invert Color: Instant Complementary Masks" }, description: { zh: "反色（Invert Color）節點把顏色變成 1 減去原本的值，常用來把黑白遮罩反過來用——例如把「哪裡有雜訊」變成「哪裡沒有雜訊」，不用重新調整上游節點。", en: "Invert Color computes 1 minus the original value — commonly used to flip a black/white mask, e.g. turning 'where there's noise' into 'where there isn't', without touching the upstream nodes at all." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_mix_carpaint", name: { zh: "混合節點：車漆效果", en: "Mix Shader: Car Paint" }, description: { zh: "用混合著色器（Mix Shader）把原理化 BSDF（底漆）跟光澤 BSDF（Glossy BSDF，光澤反射）混合，做出邊緣會反光的車漆材質，學會怎麼把兩個材質疊在一起。", en: "Blend a Diffuse (base coat) and a Glossy (reflective) shader with Mix Shader to get a car-paint look with edge highlights — learn how to layer two materials together." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_mix_sheer", name: { zh: "混合節點：局部穿透網紗", en: "Mix Shader: Sheer Pattern" }, description: { zh: "用紋理節點的輸出（而不是固定滑桿）當作混合著色器（Mix Shader）的 Fac，做出規律穿透的網紗/窗簾材質。", en: "Use a texture node's output (instead of a fixed slider) as Mix Shader's Fac to create a regularly-patterned sheer fabric / curtain material." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_stone", name: { zh: "做出石頭材質", en: "Make a Stone Material" }, description: { zh: "用沃羅諾伊紋理（Voronoi Texture）的細胞圖案做出石頭的斑駁感，並用同一份資料同時驅動顏色跟粗糙度，讓縫隙看起來更真實。", en: "Use Voronoi Texture's cellular pattern to create a mottled stone look, driving both color and roughness from the same data so the cracks read as more realistic." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_voronoi_mosaic", name: { zh: "沃羅諾伊馬賽克：隨機色塊拼貼", en: "Voronoi Mosaic: Random Tile Colors" }, description: { zh: "沃羅諾伊紋理（Voronoi Texture）的 Color 輸出會給每個細胞一個獨立的隨機顏色，很適合做馬賽克磁磚、卵石地板這種「每一塊顏色都不太一樣」的效果——這跟石頭教學用 Distance 做斑駁色調是完全不同的技巧。", en: "Voronoi Texture's Color output gives each cell its own random color — great for mosaic tiles, cobblestone floors, or anything where 'each patch is a slightly different color'. This is a completely different technique from the Stone tutorial's Distance-based mottling." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_white_noise", name: { zh: "白雜訊：完全隨機無規律", en: "White Noise: Fully Random, No Pattern" }, description: { zh: "白噪波紋理（White Noise Texture）跟雜訊紋理（Noise Texture）不同——它完全沒有平滑漸變，每個座標的值都互不相關，看起來像電視雜訊，適合做「完全隨機挑選」的場合。", en: "White Noise Texture differs from Noise Texture — it has no smooth gradient at all; every coordinate's value is unrelated to its neighbors, like TV static. Good for 'pick something completely at random' situations." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_vector_rotate", name: { zh: "向量旋轉：轉正貼圖角度", en: "Vector Rotate: Turning a Texture" }, description: { zh: "向量旋轉（Vector Rotate）節點可以把座標繞任意軸旋轉指定角度，常用來把貼圖的花紋角度轉正，或做出旋轉動畫的基礎。", en: "Vector Rotate spins a coordinate around any axis by a chosen angle — useful for straightening a texture's pattern, or as the basis for a rotation animation." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_brick_wall", name: { zh: "做出磚牆材質", en: "Make a Brick Wall Material" }, description: { zh: "用磚塊紋理（Brick Texture）做出磚牆的顏色圖案，再用凹凸（Bump）節點讓灰泥縫看起來真的凹下去，學會怎麼把一個節點的輸出同時當顏色與凹凸兩種用途。", en: "Use Brick Texture for the wall's color pattern, then use Bump to make the mortar lines actually look recessed — learn how one node's output can drive both color and bump at once." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_layer_weight_clearcoat", name: { zh: "層權重：清漆塗層", en: "Layer Weight: Clearcoat Finish" }, description: { zh: "層權重（Layer Weight）節點跟菲涅爾（Fresnel）很像，但多了一個更直覺的 Blend 滑桿，常用來在原本的材質上疊一層清漆/光澤塗層。", en: "Layer Weight is similar to Fresnel but adds a more intuitive Blend slider — commonly used to layer a clearcoat/gloss finish on top of a base material." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_gamma_correction", name: { zh: "伽瑪：次方曲線調中間調", en: "Gamma: A Power-Curve Midtone Adjustment" }, description: { zh: "伽瑪（Gamma）節點的運算就是 pow(顏色, gamma)——伽瑪大於 1 會讓中間調變暗，小於 1 會讓中間調變亮，常用來校正貼圖或快速調整材質的明暗曲線。", en: "The Gamma node simply computes pow(color, gamma) — values above 1 darken midtones, below 1 brighten them. Commonly used to correct texture data or quickly reshape a material's tonal curve." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_float_curve", name: { zh: "曲線編輯器：反轉粗糙度", en: "Curve Editor: Invert Roughness" }, description: { zh: "用數值曲線（Float Curve）節點拖拉出一條自訂的數值對應曲線，把雜訊紋理（Noise Texture）的明暗關係整個反過來，理解曲線編輯器比顏色漸變（Color Ramp）/映射範圍（Map Range）更自由的地方。", en: "Drag out a custom value-mapping curve with the Float Curve node to flip Noise Texture's light/dark relationship entirely — see how the curve editor is more flexible than Color Ramp or Map Range." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_rgb_curves", name: { zh: "RGB 曲線：像 Photoshop 一樣調色調", en: "RGB Curves: Tone-Mapping Like Photoshop" }, description: { zh: "RGB 曲線（RGB Curves）節點可以直接對一張顏色的明暗對應關係拖出一條自訂曲線——比亮度/對比度更自由，可以只拉暗部或只拉亮部，概念上跟 Photoshop 的曲線工具完全一樣。", en: "The RGB Curves node lets you drag out a custom tone-mapping curve for a color — more flexible than Brightness/Contrast, letting you pull just the shadows or just the highlights. The exact same concept as Photoshop's Curves tool." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_blackbody_glow", name: { zh: "色溫節點：燭光暖黃光", en: "Blackbody Node: Warm Candlelight" }, description: { zh: "用黑體（Blackbody）節點把「色溫（K）」這個攝影/燈光常用單位直接轉成物理精確的顏色，做出燭光般的暖黃發光效果。", en: "Use the Blackbody node to convert color temperature (K) — the unit photographers and lighting artists actually use — directly into a physically accurate color, for a candlelight-warm glow." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_wavelength_spectrum", name: { zh: "波長節點：雷射光譜色", en: "Wavelength Node: Laser Spectrum Colors" }, description: { zh: "波長（Wavelength）節點把可見光的物理波長（奈米）直接轉成對應的 RGB 顏色，常用來模擬雷射光或稜鏡色散這種需要物理精確光色的場合。", en: "The Wavelength node converts a visible-light wavelength (in nanometers) directly into the corresponding RGB color — useful for simulating lasers or prism dispersion where physically accurate coloring matters." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_mix_color_grime", name: { zh: "混合顏色：疊一層污漬", en: "Mix Color: Layering On Grime" }, description: { zh: "混合顏色（Mix Color）節點的相乘（Multiply）模式只會讓顏色變暗、不會變亮——這正是疊加污漬、陰影貼圖的標準做法，概念上跟 Photoshop 圖層的「色彩增值」模式一樣。", en: "Mix Color's Multiply mode can only darken, never brighten — the standard technique for layering grime or shadow maps onto a base color. The same concept as Photoshop's 'Multiply' layer blend mode." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_opal_gem_gradient", name: { zh: "蛋白石效果：雙重驅動的漸層", en: "Opal Gem: A Gradient Driven by Two Sources" }, description: { zh: "真正好看的漸層效果很少只靠單一輸入驅動——蛋白石（Opal）的變彩效果同時受「觀察角度」跟「內部雜訊結構」影響。這篇教學把菲涅爾（Fresnel）跟雜訊紋理（Noise Texture）用數學節點結合成一個驅動值，再接到顏色漸變（Color Ramp）做出比單一輸入更有機、更不規則的多彩漸層。", en: "The best-looking gradients rarely come from a single input — an opal's play-of-color depends on both viewing angle and its internal noise structure. This tutorial combines Fresnel and Noise Texture with a Math node into one driving value, feeding a Color Ramp for a more organic, irregular multicolor gradient than either input alone could produce." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_skin_sss", name: { zh: "次表面散射：皮膚材質", en: "Subsurface Scattering: Skin Material" }, description: { zh: "用次表面散射（Subsurface Scattering）節點做出皮膚特有的透光邊緣，再疊一層微弱的高光，學會這種「多層 BSDF 疊加模擬複雜有機材質」的技巧。", en: "Use the Subsurface Scattering node to get skin's characteristic translucent edge glow, then layer a subtle highlight on top — learn the 'stack multiple BSDFs' technique for complex organic materials." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_velvet_sheen", name: { zh: "Sheen BSDF：天鵝絨布料", en: "Sheen BSDF: Velvet Fabric" }, description: { zh: "絨光 BSDF（Sheen BSDF）單獨使用看不出效果，一定要疊在別的材質上面才有意義。用菲涅爾（Fresnel）控制疊加比例，做出布料逆光時邊緣才會出現的絨毛微光。", en: "Sheen BSDF does nothing meaningful on its own — it only matters layered on top of another material. Use Fresnel to control the blend so the fuzzy edge glow only shows up at grazing/backlit angles, like real fabric." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_rust_weathering", name: { zh: "程序化風化：生鏽金屬", en: "Procedural Weathering: Rusted Metal" }, description: { zh: "用雜訊紋理（Noise Texture）產生的雜訊、經過顏色漸變（Color Ramp）轉成黑白遮罩，驅動混合著色器（Mix Shader）在同一個表面上混合「乾淨金屬」跟「鏽蝕」兩種材質——這是遊戲/影視資產最常用的程序化風化技巧。", en: "Use Noise Texture's output, remapped by a Color Ramp into a black/white mask, to drive Mix Shader blending 'clean metal' and 'rust' on the same surface — the classic procedural weathering technique used throughout games and VFX." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_normal_compare", name: { zh: "法線節點：手動方向比較", en: "Normal Node: Manual Direction Comparison" }, description: { zh: "法線（Normal）節點讓你手動指定一個方向，再輸出它跟表面真正法線的夾角餘弦值（Dot）——可以做出「只有朝向某個方向的表面才會怎樣」的效果，例如模擬固定角度的光照方向。", en: "The Normal node lets you manually specify a direction and outputs the cosine of the angle (Dot) between it and the surface's real normal — useful for effects like 'only surfaces facing this direction do X', such as simulating a fixed light direction." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_vector_curves", name: { zh: "向量曲線：非線性扭曲法線", en: "Vector Curves: Nonlinearly Warp a Normal" }, description: { zh: "向量曲線（Vector Curves）跟 RGB 曲線概念相同，只是套用在向量（例如法線）上而不是顏色——可以做出比線性運算更細膩的方向扭曲效果。", en: "Vector Curves is the same concept as RGB Curves, but applied to a vector (like a normal) instead of a color — enabling more nuanced direction warping than a linear operation." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_vector_transform_spaces", name: { zh: "向量變換：認識座標空間", en: "Vector Transform: Understanding Coordinate Spaces" }, description: { zh: "同一個方向在「物體」「世界」「攝影機」三種座標空間下的數值都不一樣。向量變換（Vector Transform）節點負責在它們之間換算——把世界座標下的「正上方」轉到攝影機座標，你會發現數值隨著鏡頭角度即時改變。", en: "The same direction has different numeric values in Object, World, and Camera coordinate spaces. Vector Transform converts between them — convert World-space 'straight up' into Camera space and watch the values change live as the camera orbits." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_layer_stack_blend", name: { zh: "疊圖技巧：多層混合模式堆疊", en: "Layer Stacking: Chaining Multiple Blend Modes" }, description: { zh: "真實的材質貼圖很少只疊一層——通常是「底色 → 正片疊底疊污漬 → 濾色疊磨損高光」這樣一層一層疊上去，跟 Photoshop 的圖層堆疊完全同一個概念。這篇教學串接兩個混合顏色（Mix Color）節點，各自用不同的混合模式，做出「又髒又有磨損高光」的複雜表面。", en: "Real-world material textures are rarely a single layer — usually it's 'base color → Multiply in grime → Screen in worn highlights', stacked one after another, exactly like layers in Photoshop. This tutorial chains two Mix Color nodes with different blend modes to create a surface that's both dirty and has worn highlights." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_terrain_height_map", name: { zh: "地形上色：多停駐點顏色漸變＋細節疊圖", en: "Terrain Coloring: A Multi-Stop Ramp Plus Detail Overlay" }, description: { zh: "遊戲美術很常用一條「高度→顏色」的顏色漸變幫地形自動上色：低處是水、中間是草地、高處是雪。這篇教學用雜訊紋理（Noise Texture）模擬高度，接上一條 6 個停駐點的顏色漸變做出水／沙／草／岩／雪的分層配色，再疊一層濾色模式的細節紋理增加表面變化，示範「大範圍色彩分區」跟「小範圍表面細節」怎麼同時存在。", en: "Game art often auto-colors terrain with a single 'height → color' ramp: low = water, mid = grass, high = snow. This tutorial uses a Noise Texture to stand in for height, feeds it through a 6-stop Color Ramp for a water/sand/grass/rock/snow palette, then screens in a detail texture on top — showing how large-scale color zoning and small-scale surface detail can coexist." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_car_paint_flakes", name: { zh: "金屬車漆：疊上細小亮片", en: "Metallic Car Paint: Adding Tiny Flakes" }, description: { zh: "真正的金屬烤漆不是均勻的一片顏色——漆裡混了無數微小的金屬亮片，只有極少數角度/位置會反出銳利的小亮點。這篇教學用沃羅諾伊紋理（Voronoi Texture）的距離（Distance）輸出配上顏色漸變（Color Ramp）做出「大部分是黑、只有細胞中心是白」的稀疏亮點遮罩，再用加法著色器（Add Shader）把亮點當發光疊在原本的車漆底色上——這是兩個獨立材質相加、而不是取代彼此的疊圖概念。", en: "Real metallic car paint isn't a flat color — it's full of microscopic metal flakes, and only a few spots catch a sharp bright glint. This tutorial uses Voronoi Texture's Distance output with a Color Ramp to build a sparse 'mostly black, bright only at cell centers' mask, then uses an Add Shader to layer that as glow on top of the base paint color — two independent materials summed together, not replacing one another." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_stained_glass", name: { zh: "彩色玻璃窗：用顏色漸變做調色盤化", en: "Stained Glass: Using a Color Ramp to Posterize a Palette" }, description: { zh: "沃羅諾伊紋理的顏色（Color）輸出，每個細胞都是一個完全隨機的顏色——顏色太雜、不像真正的彩色玻璃窗（通常只用幾種固定色調）。這篇教學示範顏色漸變（Color Ramp）的另一種用法：不是拿來做平滑漸層，而是設很多組「位置很接近、顏色卻不一樣」的停駐點，把連續的隨機值強制«量化»成少數幾種固定色調——這叫做調色盤化（Posterize），是很多风格化渲染的核心技巧。再疊一層黑色縫隙線，做出完整的彩色玻璃窗效果。", en: "Voronoi Texture's Color output gives every cell a fully random color — too chaotic to look like a real stained-glass window (which typically uses just a handful of fixed hues). This tutorial shows a different use of Color Ramp: instead of a smooth gradient, you set many stop-pairs positioned very close together with different colors, forcing a continuous random value to snap into a small, fixed palette — a technique called posterizing, central to a lot of stylized rendering. Then a layer of black grout lines completes the stained-glass look." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_channel_packing", name: { zh: "色彩通道打包：一張貼圖塞三個遮罩", en: "Channel Packing: Three Masks in One Texture" }, description: { zh: "遊戲美術常把三個各自獨立的黑白遮罩（例如粗糙度、金屬度、AO）分別塞進一張貼圖的 R、G、B 三個色版，存成一張圖而不是三張，省空間也省讀取次數——這叫做「通道打包」。這篇教學用合併顏色（Combine Color）把三個不相關的紋理各自塞進一個顏色的 R/G/B，再用分離顏色（Separate Color）把它們各自拆回來、分別驅動材質的不同參數，示範打包前後資訊完全沒有遺失。", en: "Game art often packs three independent black/white masks (e.g. roughness, metallic, AO) into a single texture's R, G, B channels instead of three separate images — saving space and texture reads. This is called channel packing. This tutorial uses Combine Color to stuff three unrelated textures into one color's R/G/B, then Separate Color to pull them back apart and drive different material parameters — proving no information is lost in the round trip." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_torn_holes", name: { zh: "撕裂破洞：局部穿透效果", en: "Torn Holes: Partial Transparency" }, description: { zh: "破葉子、蟲蛀的布料、生鏽穿孔的鐵皮，這些「大部分完整、局部有洞」的材質，做法都一樣：用透明 BSDF（Transparent BSDF）當作「洞」，用混合著色器（Mix Shader）把它跟原本的材質混合，再用色彩帶（Color Ramp）做出的黑白遮罩控制哪裡有洞、哪裡沒有——這篇教學專門示範 Transparent BSDF 這個之前沒用過的節點。", en: "Torn leaves, moth-eaten fabric, rusted-through sheet metal — these 'mostly solid, holes here and there' materials all use the same technique: Transparent BSDF as the 'hole', Mix Shader to blend it with the base material, and a Color Ramp mask to control where the holes appear. This tutorial focuses on Transparent BSDF, a node not used elsewhere in this site." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_handbuilt_clearcoat", name: { zh: "手工組出清漆效果：拆解 Principled BSDF 的內部原理", en: "Hand-Built Clearcoat: How Principled BSDF Works Under the Hood" }, description: { zh: "原理化 BSDF（Principled BSDF）的 Clearcoat（清漆）其實不是魔法——本質就是「用 Fresnel 混合兩層材質」：底層是霧面的漫射 BSDF（Diffuse BSDF），表層是接近鏡面的光澤 BSDF（Glossy BSDF），越靠邊緣角度越容易看到表層清漆的反光。這篇教學帶你用最原始的 3 個節點（Diffuse BSDF／Glossy BSDF／Fresnel）親手組出這個效果，順便介紹兩個材質圖裡最基本的常數節點：RGB 跟數值（Value）。", en: "Principled BSDF's Clearcoat isn't magic — it's really just 'blend two materials by Fresnel': a matte Diffuse BSDF underneath, a near-mirror Glossy BSDF on top, with the top coat becoming more visible at grazing angles. This tutorial builds that effect by hand from 3 primitive nodes (Diffuse BSDF / Glossy BSDF / Fresnel), and along the way introduces the two most basic constant nodes in any material graph: RGB and Value." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_compass_material", name: { zh: "羅盤材質：用向量數學指向固定方向", en: "Compass Material: Pointing a Fixed Direction with Vector Math" }, description: { zh: "菲涅爾（Fresnel）驅動的效果永遠只跟「攝影機角度」有關，轉動攝影機時亮邊會一直跟著跑。但如果你想要一個「不管怎麼轉動攝影機，永遠固定指向某個方向」的效果（例如物體上一個固定的發光標記），就要換一種做法：用向量數學（Vector Math）的內積（Dot Product）算出「表面法線」跟「你指定的固定方向」有多接近，越接近就越亮。這篇教學示範這個技巧，順便介紹怎麼用數值（Value）節點把一個常用參數抽出來獨立調整。", en: "Fresnel-driven effects only ever depend on camera angle — the bright edge always follows the camera as you orbit. But if you want an effect that stays fixed to a chosen direction in object space (like a fixed glowing marker on an object) regardless of camera movement, you need a different technique: Vector Math's Dot Product measures how closely the surface normal aligns with a direction you pick — the closer, the brighter. This tutorial builds that effect, and shows how to extract a frequently-tuned parameter into its own Value node." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_detail_baking_workflow", name: { zh: "細節烘焙工作流：法線貼圖＋向量位移", en: "Detail Baking Workflow: Normal Map + Vector Displacement" }, description: { zh: "遊戲/影視最常見的高模轉低模流程：先在雕刻軟體做出超高精度的模型，再把細節「烘焙」成兩張貼圖——法線貼圖（Normal Map，做出光影細節，不改變輪廓）跟向量位移貼圖（Vector Displacement Map，真的把頂點往外推，改變輪廓）——貼回低模上。這篇教學示範完整接線流程：UV 貼圖（UV Map）指定座標、圖像紋理（Image Texture）讀圖、法線貼圖節點解出光影方向、向量位移節點搭配「把 0-1 貼圖數值解碼回 -1 到 1 方向」的技巧做出真正的幾何位移。", en: "The classic high-poly-to-low-poly pipeline: sculpt extreme detail in a dedicated app, then bake it into two textures — a Normal Map (shading detail, silhouette unchanged) and a Vector Displacement Map (actually pushes vertices, changing the silhouette) — and apply both to the low-poly mesh. This tutorial wires up the whole chain: UV Map for coordinates, Image Texture to read the maps, Normal Map to decode shading direction, and Vector Displacement paired with the 'decode a 0-1 map value back into a -1..1 direction' technique for real geometric displacement." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_displacement_terrain", name: { zh: "真正的位移：凹凸地形", en: "True Displacement: Bumpy Terrain" }, description: { zh: "凹凸（Bump）只是假的光影，位移（Displacement）會真的把頂點往外推。用沃羅諾伊紋理（Voronoi Texture）驅動位移節點，做出真的凹凸不平、輪廓也會改變的地形表面。", en: "Bump only fakes the lighting — Displacement actually pushes vertices outward. Drive a Displacement node with Voronoi Texture to create a surface whose silhouette genuinely bumps and warps." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_ridged_terrain", name: { zh: "山脊多重分形：裂紋岩石質感", en: "Ridged Multifractal: Cracked Rock Look" }, description: { zh: "雜訊紋理（Noise Texture）除了預設的 fBM（柔和雲霧感）之外，還有 Ridged Multifractal 這種會刻出銳利山脊狀裂紋的類型，很適合做岩石、峽谷、乾裂地面的質感。", en: "Beyond the default fBM (soft, cloud-like noise), Noise Texture also has Ridged Multifractal — a type that carves sharp, ridge-like creases. Great for rock, canyons, and cracked ground." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_hsv_channel_pack", name: { zh: "分離顏色：只調飽和度不動色相", en: "Separate Color: Adjust Only Saturation" }, description: { zh: "分離顏色（Separate Color）跟合併顏色（Combine Color）現在支援 HSV／HSL 模式，可以把色相、飽和度、明度拆開單獨處理——這裡示範只把飽和度調高，讓沃羅諾伊紋理的隨機色塊變得更鮮豔，色相跟明暗完全不受影響。", en: "Separate Color and Combine Color now support HSV/HSL modes, letting you split hue, saturation, and value apart and adjust just one. Here we boost only saturation on a Voronoi Texture's random cell colors, making them more vivid without touching hue or brightness." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_voronoi_distance_metrics", name: { zh: "沃羅諾伊：用距離度量改變細胞形狀", en: "Voronoi: Reshape Cells with Distance Metric" }, description: { zh: "沃羅諾伊紋理（Voronoi Texture）的距離度量（Distance Metric）決定細胞邊界的形狀：歐式是圓潤的、切比雪夫是方形的、閔可夫斯基（Minkowski）則用 Exponent 插槽在兩者之間連續變化——Exponent 越小越像鑽石/菱形，越大越像正方形。", en: "Voronoi Texture's Distance Metric determines each cell's boundary shape: Euclidean gives rounded cells, Chebychev gives square ones, and Minkowski lets you slide continuously between them via its Exponent input — lower values look diamond-shaped, higher values approach square." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_principled_bsdf_tour", name: { zh: "認識原理化 BSDF：材質的控制中心", en: "Get to Know Principled BSDF: Your Material's Control Panel" }, description: { zh: "原理化 BSDF（Principled BSDF）幾乎是所有材質的起點，光是這一個節點就能做出塑膠、金屬、發光、玻璃感等各種效果。這篇教學不接任何新節點，純粹帶你把 Base Color、Roughness、Metallic、Emission、Alpha 五個最關鍵的插槽都動過一次，建立完整的第一印象。", en: "Principled BSDF is nearly every material's starting point — this single node can produce plastic, metal, glow, or glass-like looks. This tutorial doesn't wire in any new nodes at all; it just walks you through Base Color, Roughness, Metallic, Emission, and Alpha — the five most important sliders — so you get a complete first impression of what each one does." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_color_ramp_tour", name: { zh: "認識顏色漸變：材質上色的核心工具", en: "Get to Know Color Ramp: The Core Coloring Tool" }, description: { zh: "顏色漸變（Color Ramp）幾乎是所有程序化材質上色的樞紐——把 Noise、Voronoi 這類紋理輸出的 0-1 數值，轉換成你想要的任何配色。這篇帶你從最基本的黑白漸層開始，學會新增停駐點、切換色彩空間、切換插值方式，建立完整的操作直覺。", en: "Color Ramp is the hub for coloring almost every procedural material — it turns a 0-1 value from textures like Noise or Voronoi into any color scheme you want. This tutorial starts from a basic black-to-white gradient and builds up to adding stops, switching color spaces, and changing interpolation, giving you a full feel for the tool." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_image_texture_tour", name: { zh: "認識圖像紋理：貼上你自己的圖片", en: "Get to Know Image Texture: Using Your Own Image" }, description: { zh: "圖像紋理（Image Texture）是最常用的紋理節點——直接讀取你上傳的照片或素材圖當材質。這篇帶你認識三個關鍵設定：延展模式（Extension）、插值（Interpolation）、色彩空間（Color Space），尤其色彩空間選錯會讓法線貼圖、粗糙度圖整個跑掉，是很多初學者會踩的坑。", en: "Image Texture is the most-used texture node — it reads an uploaded photo or texture map directly. This tutorial covers three key settings: Extension, Interpolation, and Color Space. Getting Color Space wrong especially can throw off normal maps and roughness maps entirely — a common beginner trap." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_math_operations_tour", name: { zh: "認識 Math 節點：切換運算看四種效果", en: "Get to Know the Math Node: Four Operations, Four Looks" }, description: { zh: "Math 節點的運算（Operation）下拉選單有 30 幾種選項，光看清單很難想像差別。這篇用同一條「雜訊→Math→發光」的線路，切換 4 種代表性運算（相加、吸附、大於、正弦），讓你直接看到「函式／捨入／比較／三角函數」這四大分類分別長什麼樣子。", en: "The Math node's Operation dropdown has 30-some options — hard to picture from the list alone. This tutorial keeps the same 'Noise → Math → Emission' wiring and switches through 4 representative operations (Add, Snap, Greater Than, Sine) so you can directly see what the Functions/Rounding/Comparison/Trigonometric categories each look like." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_noise_texture_tour", name: { zh: "認識雜訊紋理：Detail、Distortion、Type 一次搞懂", en: "Get to Know Noise Texture: Detail, Distortion, and Type" }, description: { zh: "雜訊紋理（Noise Texture）幾乎是所有程序化材質的起點，但 Detail／Roughness／Distortion 這些插槽、還有 5 種 Noise Type 到底差在哪，光看名字很難想像。這篇用最直接的方式，一個一個調給你看。", en: "Noise Texture is the starting point for nearly every procedural material, but it's hard to picture what Detail/Roughness/Distortion actually do, or how the 5 Noise Types differ, just from their names. This tutorial adjusts them one at a time so you can see directly." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_mapping_types_tour", name: { zh: "映射節點的 4 種 Type：Point、Vector、Texture、Normal", en: "Mapping's 4 Types: Point, Vector, Texture, Normal" }, description: { zh: "映射（Mapping）節點的類型（Type）下拉選單有 4 種：Point、Texture、Vector、Normal，平常最容易被忽略。這篇專門示範這 4 種的實際差別——尤其 Point 跟 Vector 的差異只有一個：位置（Location）到底有沒有作用。", en: "Mapping's Type dropdown has 4 options — Point, Texture, Vector, Normal — that are easy to overlook. This tutorial specifically demonstrates what each one actually does, especially the one difference between Point and Vector: whether Location has any effect at all." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_vector_math_tour", name: { zh: "認識向量數學：長度、正規化、外積", en: "Get to Know Vector Math: Length, Normalize, Cross Product" }, description: { zh: "向量數學（Vector Math）的內積（Dot Product）已經在「羅盤材質」教學教過；這篇換個角度，帶你認識幾何（Geometry）分類的長度（Length）、正規化（Normalize），還有外積（Cross Product）——用長度做出一個以物體中心為圓心的放射狀漸層，直接看到效果。", en: "Vector Math's Dot Product is already covered in the 'Compass Material' tutorial. This one takes a different angle, covering the Geometry category's Length and Normalize, plus Cross Product — using Length to build a radial gradient centered on the object, so you see the effect directly." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_add_shader_tour", name: { zh: "認識加法著色器：跟 Mix Shader 差在哪", en: "Get to Know Add Shader: How It Differs from Mix Shader" }, description: { zh: "加法著色器（Add Shader）長得跟混合著色器（Mix Shader）很像，都是把兩個材質接在一起，但 Add 沒有 Fac 比例——兩個輸入是直接相加，不是內插。這篇用兩個發光（Emission）節點直接示範這個差異：同樣兩個輸入，Add 出來的畫面會比 Mix（50/50）明顯更亮。", en: "Add Shader looks similar to Mix Shader — both combine two shaders — but Add has no Fac ratio: the two inputs are summed directly, not blended. This tutorial demonstrates the difference directly with two Emission nodes: for the same two inputs, Add's result is noticeably brighter than Mix at a 50/50 split." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_bump_tour", name: { zh: "認識凹凸節點：假造出來的立體感", en: "Get to Know Bump: Faking Surface Detail" }, description: { zh: "凹凸（Bump）幾乎出現在所有有質感的材質裡——用一個灰階高度值假造出表面凹凸的光影效果，不會真的改變幾何形狀。這篇帶你認識 Height、Strength 兩個插槽，還有初學者最常忘記的一件事：Bump 的輸出一定要接到法線（Normal）插槽才會有效果。", en: "Bump shows up in nearly every textured material — it fakes surface bumps' lighting from a grayscale height value, without actually changing the geometry. This tutorial covers Height and Strength, plus the one thing beginners most often forget: Bump's output must be connected to a Normal socket to have any effect at all." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_checker_texture_tour", name: { zh: "認識棋盤格紋理：理解座標系統的最佳工具", en: "Get to Know Checker Texture: The Best Tool for Understanding Coordinates" }, description: { zh: "棋盤格紋理（Checker Texture）看起來很簡單，卻是理解「座標系統」最好的工具——格子如果扭曲、拉伸、密度改變，代表座標本身在變化。這篇帶你認識 Color 1/2、Scale，還有換一個座標來源會怎麼影響格子。", en: "Checker Texture looks simple, but it's the best tool for understanding coordinate systems — if the squares stretch, distort, or change density, that tells you the coordinate itself is changing. This tutorial covers Color 1/2, Scale, and how swapping the coordinate source affects the pattern." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_map_range_tour", name: { zh: "認識映射範圍：4 種插值方式一次看懂", en: "Get to Know Map Range: 4 Interpolation Modes" }, description: { zh: "映射範圍（Map Range）把數值從一個範圍等比例換算到另一個範圍，是整理材質圖的重要工具。這篇帶你認識它的插值方式——線性（Linear）、階梯（Stepped）、平滑／更平滑（Smoothstep／Smootherstep）——還有夾值（Clamp）開關，用同一張雜訊紋理一次一種切換給你看差異。", en: "Map Range rescales a value from one range into another — an important tool for tidying up a material graph. This tutorial covers its interpolation modes — Linear, Stepped, Smoothstep/Smootherstep — and the Clamp toggle, switching through them one at a time on the same Noise Texture so you can see the difference." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_wave_texture_tour", name: { zh: "認識波浪紋理：Bands、Rings、剖面一次搞懂", en: "Get to Know Wave Texture: Bands, Rings, and Profile" }, description: { zh: "波浪紋理（Wave Texture）能做出規律的條紋或環狀波紋，是木紋、水波、金屬拉絲的常見基礎。這篇帶你認識波形（Bands/Rings）、剖面（Profile）、扭曲（Distortion）這幾個關鍵設定，一次一個切給你看。", en: "Wave Texture produces regular bands or rings — a common basis for wood grain, water ripples, or brushed metal. This tutorial covers Wave Type (Bands/Rings), Profile, and Distortion, switching one at a time so you can see each effect." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_fresnel_tour", name: { zh: "認識菲涅爾：邊緣反光是怎麼來的", en: "Get to Know Fresnel: Where Edge Reflections Come From" }, description: { zh: "現實中幾乎所有材質都是「正面看較不反光、側邊掠視角度反光更強」，這就是菲涅爾（Fresnel）效應。這篇先讓你直接看到 Fresnel 輸出的灰階樣子（中心暗、邊緣亮），再示範它最常見的實際用途：驅動 Mix Shader 疊一層邊緣反光。", en: "Almost every real material reflects less head-on and more at grazing angles — the Fresnel effect. This tutorial first shows you Fresnel's raw grayscale output (dark center, bright rim), then its most common real use: driving a Mix Shader to layer in edge reflection." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_mix_color_blend_modes_tour", name: { zh: "認識混合顏色：正片疊底、濾色、疊加怎麼選", en: "Get to Know Mix Color: Multiply, Screen, Overlay" }, description: { zh: "混合顏色（Mix Color）的混合模式（Blend Mode）下拉選單有 18 種，光看名字很難決定要選哪個。這篇用固定的兩個顏色，切換 3 種最常用的模式——正片疊底（Multiply，讓畫面變暗）、濾色（Screen，讓畫面變亮，效果跟「去掉黑色」很像）、疊加（Overlay，同時兼顧兩種效果），讓你直接看到差異、知道什麼情境該選哪個。", en: "Mix Color's Blend Mode dropdown has 18 options — hard to know which to pick from names alone. This tutorial uses two fixed colors and switches through 3 of the most-used modes: Multiply (darkens), Screen (brightens — similar to 'removing black'), and Overlay (does a bit of both), so you can see the difference directly and know which to reach for." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_edge_wear_mask", name: { zh: "邊緣磨損：油漆刮到露出金屬", en: "Edge Wear: Paint Chipping to Bare Metal" }, description: { zh: "遊戲美術最常用的一招：邊緣磨損（Edge Wear）——物體的平坦處保留原本的漆面，稜角/邊緣則因為長期碰撞磨損露出底下的金屬。做法是用菲涅爾（Fresnel）算出「這裡有多接近邊緣」，接一個切成硬邊的顏色漸變（Color Ramp，常量 Constant 插值）做出「非黑即白」的遮罩，再用這個遮罩驅動混合著色器（Mix Shader）切換兩種完全不同的材質。", en: "A classic game-art technique: edge wear — flat surfaces keep their paint, while edges/corners show bare metal from repeated impact. The trick: Fresnel measures 'how close to an edge this is', a hard-edged Color Ramp (Constant interpolation) turns that into an all-or-nothing mask, and the mask drives a Mix Shader to swap between two completely different materials." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_layer_weight_facing_vs_fresnel", name: { zh: "層權重的兩個輸出：Fresnel 跟 Facing 差在哪", en: "Layer Weight's Two Outputs: Fresnel vs Facing" }, description: { zh: "層權重（Layer Weight）節點有兩個輸出：Fresnel 跟 Facing，很多人只用過 Fresnel 那個。這篇直接對比兩者——Fresnel 的曲線形狀可以用 Blend 滑桿調整（越大越集中在邊緣），Facing 是固定公式、Blend 對它完全沒有作用。搞懂這個差異，才知道什麼情境該選哪個。", en: "Layer Weight has two outputs — Fresnel and Facing — but most people only ever use Fresnel. This tutorial directly compares them: Fresnel's curve shape is tunable via the Blend slider (higher = more concentrated at the edges), while Facing is a fixed formula that Blend doesn't affect at all. Understanding this difference tells you which one to reach for." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_candle_wax_glow", name: { zh: "蠟燭材質：次表面散射＋加法著色器疊光", en: "Candle Wax: Subsurface Scattering + Add Shader Glow" }, description: { zh: "蠟燭的蠟身半透光、內部又像被燭火照亮，是次表面散射（Subsurface Scattering）的經典應用之一。這篇示範怎麼把 SSS 的邊緣透光效果，跟一層額外的暖黃色發光（Emission）疊加起來——用加法著色器（Add Shader，不是 Mix Shader）疊加，才能讓「原本的透光」跟「額外的燭光」是真的相加變亮，而不是被平均掉。", en: "Candle wax's soft translucency, lit from within by the flame, is a classic Subsurface Scattering use case. This tutorial layers SSS's edge translucency with an extra warm-yellow Emission glow — using Add Shader (not Mix Shader) so the 'built-in translucency' and the 'extra candlelight' genuinely add up brighter instead of getting averaged down." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_frosted_glass", name: { zh: "毛玻璃：用雜訊驅動玻璃的粗糙度", en: "Frosted Glass: Driving Glass Roughness with Noise" }, description: { zh: "浴室毛玻璃是「玻璃 BSDF（Glass BSDF）＋不均勻粗糙度」做出來的——不是整片統一模糊，而是有細緻顆粒感的霧面。這篇示範把雜訊紋理（Noise Texture）接到玻璃的粗糙度（Roughness），再用映射範圍（Map Range）把範圍收在一個合理的區間，避免霧面收過頭變成完全不透光的白霧。", en: "Bathroom frosted glass is Glass BSDF plus uneven roughness — not a uniform blur, but a finely grained frost. This tutorial wires Noise Texture into Glass BSDF's Roughness, then uses Map Range to keep the result in a reasonable range so the frosting doesn't go so far it turns into an opaque white haze." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_puddle_wetness", name: { zh: "積水地面：程序化的濕潤斑塊", en: "Puddle Ground: Procedural Wet Patches" }, description: { zh: "淋濕的地面會在低窪處積出一灘灘光滑的水漬，其餘地方仍然是乾燥粗糙的。這篇用沃羅諾伊紋理（Voronoi Texture）的平滑 F1（Smooth F1）特徵天生的圓潤斑塊形狀，接一個硬邊的顏色漸變（Color Ramp，常量 Constant）做出積水遮罩，驅動混合著色器（Mix Shader）在「乾燥粗糙」跟「濕潤光滑」兩種材質間切換——這次遮罩是由紋理（而非視角）決定，跟邊緣磨損那篇正好互補。", en: "Wet ground pools into smooth patches in low spots while staying dry and rough elsewhere. This tutorial uses Voronoi Texture's Smooth F1 feature — whose blob-like shape is a natural fit — piped through a hard-edged Color Ramp (Constant) to build a puddle mask, driving a Mix Shader between 'dry and rough' and 'wet and glossy'. This time the mask comes from a texture, not the viewing angle — a nice complement to the edge-wear tutorial." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_toon_style_banding", name: { zh: "風格化色階：用硬邊漸變仿卡通分色", en: "Stylized Banding: Faking Cel Shading with Hard-Edge Ramps" }, description: { zh: "本沙盒的卡通 BSDF（Toon BSDF）跟 Shader to RGB 都因為需要『打光完成之後』才能介入而無法支援即時預覽（這兩個節點都需要先算出最終光影、才能把它硬分成幾個色階，但本沙盒的架構是先算好材質參數、再一次交給 Three.js 統一打光，順序反過來了）。這篇教一個不需要那兩個節點也能做到的替代做法：用菲涅爾（Fresnel）＋多停駐點的硬邊顏色漸變（Color Ramp，常量 Constant），做出「隨視角分色」的風格化色塊——不是真正依光照方向分色的卡通渲染，但一樣能做出手繪分色感的視覺效果，這篇會誠實說明兩者的差異在哪。", en: "This sandbox's Toon BSDF and Shader to RGB can't support live preview because they need to intervene *after* lighting is resolved (both require the final shading result before banding it into discrete steps — but this sandbox's architecture computes material parameters first, then hands everything to Three.js for lighting in one pass, the opposite order). This tutorial teaches a workaround that doesn't need either node: Fresnel plus a multi-stop hard-edge Color Ramp (Constant) to fake view-angle-based color banding. It's not true light-direction-based cel shading, but it gets a similar hand-painted, banded look — and this tutorial is upfront about exactly where the two differ." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_brick_texture_tour", name: { zh: "磚塊紋理完整導覽：形狀參數全解析", en: "Brick Texture Full Tour: All the Shape Parameters" }, description: { zh: "做磚牆教學（`brick_wall`）只用了預設形狀，磚塊紋理（Brick Texture）其實還有一整組能改變磚塊排法的參數：寬高比、位移週期、壓縮週期、顏色偏向。這篇專門帶你把這些參數一個個轉過一輪，理解怎麼調出瘦高磚、跑道式砌法、或風化不規則的牆面。", en: "The brick wall tutorial only used the default shape. Brick Texture actually has a whole set of parameters that reshape the brick layout: aspect ratio, offset frequency, squash frequency, and color bias. This tutorial walks through each one so you understand how to get tall narrow bricks, running-bond masonry, or a weathered irregular wall." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_dual_tone_fabric_colorway", name: { zh: "雙色織布：用 HSV 一次換掉整個配色", en: "Two-Tone Fabric: Recoloring the Whole Pattern with HSV" }, description: { zh: "做好一個雙色織紋圖案之後，如果想要換一個配色（例如藍白格改成綠白格），不需要重新調整顏色漸變（Color Ramp）裡的每一個停駐點——接一個色相/飽和度/明度（Hue Saturation Value）節點在後面，轉一下 Hue，整組配色會保持原本的明暗對比跟圖案，一次全部換色。這篇示範這個「圖案跟配色分開處理」的實用技巧。", en: "Once you've built a two-tone weave pattern, switching its colorway (say, blue-and-white to green-and-white) doesn't require re-tuning every Color Ramp stop — pipe a Hue Saturation Value node afterward, turn Hue, and the whole colorway shifts at once while keeping the original contrast and pattern. This tutorial demonstrates that 'separate the pattern from its colorway' technique." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_transmission_shaders_compared", name: { zh: "三種穿透著色器比一比：Glass、Refraction、Translucent", en: "Three Transmission Shaders Compared: Glass, Refraction, Translucent" }, description: { zh: "玻璃 BSDF（Glass BSDF）、折射 BSDF（Refraction BSDF）、半透射 BSDF（Translucent BSDF）都跟「光線穿透」有關，很容易搞混。這篇用同一顆球依序切換三者，直接感受差異：Glass 有菲涅爾（Fresnel）驅動的反射，側邊角度會明顯變亮/更不透明；Refraction 只有純折射穿透、完全沒有反射，透明度只跟粗糙度有關、不會隨視角變化；Translucent 則完全不是「看穿過去」，而是像葉子一樣讓光在物體內部散開、邊緣透出微光。", en: "Glass BSDF, Refraction BSDF, and Translucent BSDF are all about light passing through, and easy to mix up. This tutorial switches through all three on the same sphere so you can feel the difference directly: Glass has Fresnel-driven reflection that visibly brightens/opaques at grazing angles; Refraction is pure transmission with zero reflection — its transparency depends only on roughness, not viewing angle; Translucent isn't about 'seeing through' at all — it's more like a leaf, letting light scatter inside the object and glow faintly at the edges." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_bump_vs_displacement_compared", name: { zh: "Bump vs Displacement：同一份高度資料，直接比一比", en: "Bump vs Displacement: Same Height Data, Direct Comparison" }, description: { zh: "凹凸（Bump）教學跟位移（Displacement）教學分別存在，但沒有人直接把兩者放在同一張圖上比較過。這篇用同一份雜訊高度資料，先接 Bump、再多接一份 Displacement，讓你親眼看到「輪廓完全沒變，只是光影騙術」跟「輪廓真的凹凸」的差異，不用只靠文字想像。", en: "Bump and Displacement each have their own tutorial, but nobody's put them side by side on the same graph. This one feeds the same noise height data into both — first Bump, then Displacement too — so you can see with your own eyes that one is pure lighting trickery (silhouette unchanged) while the other genuinely deforms the surface, instead of just reading about the difference." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_sss_texture_driven_color", name: { zh: "次表面散射也能接紋理：雲霧狀玉石", en: "Subsurface Scattering Can Take a Texture Too: Cloudy Jade" }, description: { zh: "次表面散射（Subsurface Scattering）的顏色（Color）插槽平常都是接一個固定顏色，但它跟其他顏色輸入一樣，也可以接紋理。這篇用雜訊紋理＋顏色漸變驅動 SSS 的顏色，做出玉石內部深淺不一的雲霧狀翠綠紋理，而不是死板的單一綠色。", en: "Subsurface Scattering's Color socket is usually wired to one fixed color, but like any other color input, it can take a texture too. This tutorial drives SSS's color with a Noise Texture through a Color Ramp, creating jade's cloudy internal green veining instead of one flat, lifeless green." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_mask_strength_scaling", name: { zh: "把遮罩調含蓄一點：用 Math 縮小整體影響力", en: "Taming a Mask: Scale Down Its Overall Influence with Math" }, description: { zh: "拿一個 0-1 的雜訊直接當混合著色器（Mix Shader）的 Fac，效果常常太搶戲——兩種材質各佔一半畫面，而不是「主要是 A、偶爾露一點 B」的含蓄效果。這篇教一個簡單技巧：在雜訊跟 Fac 中間插一個數學（Math）節點做「相乘」，把整段 0-1 的範圍直接壓扁到很小的區間（例如 0-0.15），讓次要材質只在少數地方低調地透出來。", en: "Feeding a raw 0-1 noise straight into a Mix Shader's Fac often looks too loud — two materials split roughly 50/50, instead of 'mostly A, with B subtly peeking through'. This tutorial teaches a simple trick: insert a Math node set to Multiply between the noise and the Fac, compressing the whole 0-1 range down to a small band (e.g. 0-0.15), so the secondary material only shows up sparingly and tastefully." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_voronoi_nsphere_bump_clusters", name: { zh: "沃羅諾伊做圓潤凸起：N-球半徑接凹凸", en: "Rounded Bumps with Voronoi: N-Sphere Radius into Bump" }, description: { zh: "沃羅諾伊（Voronoi）接凹凸（Bump）最常見的做法是用「到邊緣的距離」做出裂縫/溝紋，但如果想要的是一顆顆分開、圓潤的凸起（藤壺、鵝卵石、疙瘩），該換成 N-球半徑（N-Sphere Radius）——這篇直接對比兩種特徵接凹凸的差異，讓你知道什麼情境該選哪一個。", en: "The usual Voronoi-into-Bump recipe uses Distance to Edge for cracks/grooves, but if you want separate, rounded individual bumps (barnacles, pebbles, warts), switch to N-Sphere Radius instead — this tutorial directly compares both features driving Bump so you know which to reach for." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_checker_color_vs_fac", name: { zh: "棋盤格的兩個輸出：Color 跟 Fac 差在哪", en: "Checker's Two Outputs: Color vs Fac" }, description: { zh: "棋盤格紋理（Checker Texture）有兩個輸出：Color（直接兩色）跟 Fac（灰階 0/1）。很多人只用過 Color，但 Fac 才是拿棋盤格來切換「材質種類」（不只是顏色）的關鍵——這篇示範接 Fac 到混合著色器，做出真的一半塑膠、一半金屬的棋盤格，而不是同一種材質換兩個顏色。", en: "Checker Texture has two outputs: Color (two colors directly) and Fac (a 0/1 grayscale mask). Most people only ever use Color, but Fac is the key to using Checker to switch entire material types (not just colors) — this tutorial wires Fac into a Mix Shader to build a checkerboard that's genuinely half plastic, half metal, not just one material in two colors." }, level: { zh: "入門", en: "Beginner" } },
  { id: "tutorial_wave_rings_multi_look", name: { zh: "同一張圖，三種長相：波浪環狀模式的百變用途", en: "One Graph, Three Looks: Wave Rings' Many Disguises" }, description: { zh: "波浪紋理的環狀模式（Rings）長得都一樣（同心圓），但只要換顏色漸變的配色跟扭曲程度，就能從「木頭年輪」變成「水波漣漪」再變成「陶土拉坯痕」——這篇不換任何節點結構，只調參數，讓你體會到「很多材質的差異其實只在數值，不在接線方式」。", en: "Wave Texture's Rings mode always looks the same structurally (concentric circles), but just changing the Color Ramp's palette and the distortion amount takes it from 'wood end-grain' to 'water ripples' to 'hand-thrown pottery grooves' — this tutorial never changes the node structure, only the numbers, so you feel firsthand that many materials differ only in values, not in wiring." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_pbr_metal_vs_dielectric", name: { zh: "為什麼金屬的反光有顏色，塑膠的沒有", en: "Why Metal Reflections Are Colored, But Plastic's Aren't" }, description: { zh: "這篇不是教你「金屬度（Metallic）這個滑桿是幹嘛的」——那個很多教學都提過。這篇要講的是背後的物理原因：為什麼把同一個底色（Base Color）分別套在塑膠跟金屬上，塑膠的反光永遠是白的，金屬的反光卻是有色的。理解這個，你才會知道 Metallic 幾乎不該填 0.5 這種中間值，它其實是在切換兩種完全不同的反光模型，不是「調多金屬」的連續刻度。", en: "This isn't 'here's what the Metallic slider does' — plenty of tutorials cover that already. This one explains the physics behind it: why the same Base Color produces a plastic with a white highlight, but a metal with a colored one. Understanding this tells you Metallic almost never belongs at 0.5 — it's switching between two fundamentally different reflection models, not a continuous 'how metal-like' dial." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_pbr_roughness_microfacets", name: { zh: "為什麼粗糙度會讓反光暈開，而不是把顏色調暗", en: "Why Roughness Spreads Out Highlights Instead of Just Dimming Them" }, description: { zh: "這篇不是教「粗糙度（Roughness）滑桿越大表面越霧」——那個滑一下就看出來了。這篇要講的是背後的原因：表面其實是由無數個微小的鏡面（微表面，microfacet）組成，粗糙度調的是這些鏡面朝向有多分散，不是直接調亮度。搞懂這個，你才會知道「金屬看起來很塑膠感」十之八九是粗糙度沒調對，不是底色錯了。", en: "This isn't 'turn up Roughness and the surface looks foggier' — a single drag shows you that. This one explains why: a surface is made of countless tiny mirror-like facets (microfacets), and Roughness controls how scattered their tilt is — it doesn't directly dim anything. Understand this and you'll know that a metal 'looking plastic-y' is almost always a roughness problem, not a base color problem." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_fresnel_invert_core_glow", name: { zh: "菲涅爾反轉：核心發光、邊緣透明", en: "Inverting Fresnel: Glowing Core, Glassy Edge" }, description: { zh: "菲涅爾（Fresnel）天生是「側邊掠視角度數值高、正對鏡頭數值低」——這剛好跟「正面看得到核心發光、側邊才露出玻璃反光」的需求完全相反。這篇教一個簡單但好用的技巧：用數學（Math）節點的「相減」算出「1 減菲涅爾」，直接把整條曲線上下反過來，霓虹燈管這種材質就是這樣做出來的。", en: "Fresnel is naturally high at grazing angles and low head-on — exactly backwards from what you want when the glowing core should show head-on and the glassy reflection should appear at the edges. This tutorial teaches a simple, reusable trick: use a Math node's Subtract operation to compute '1 minus Fresnel,' flipping the curve upside down. This is exactly how the Neon Glass Tube preset works." }, level: { zh: "進階", en: "Advanced" } },
  { id: "tutorial_any_fac_as_bump_height", name: { zh: "任何 0-1 輸出都能當凹凸高度：棋盤格也可以", en: "Any 0-1 Output Can Drive Bump — Even Checker" }, description: { zh: "凹凸（Bump）的高度插槽（Height）常常被接上 Noise 或 Wave，但它其實只是一個普通的 0-1 數值插槽——任何節點只要輸出 0-1 的浮點數，都能直接接上去。這篇示範把棋盤格紋理（Checker Texture）平常只拿來切換顏色或驅動混合著色器的係數（Fac）輸出，改接進 Bump，方格本身就變成一格格真的有高低落差的突起，是鎖子甲金屬網（Chainmail Mesh）這個材質的核心技巧。", en: "Bump's Height socket is usually fed Noise or Wave, but it's really just an ordinary 0-1 float socket — any node that outputs a 0-1 float can be wired in directly. This tutorial feeds Checker Texture's Fac output — normally used only to switch colors or drive a Mix Shader — straight into Bump, turning the checker squares into a real grid of raised and recessed tiles. This is the core trick behind the Chainmail Mesh preset." }, level: { zh: "中階", en: "Intermediate" } },
  { id: "tutorial_voronoi_color_subtle_blend", name: { zh: "讓沃羅諾伊色塊變得若隱若現：低比例混色", en: "Making Voronoi Cells Subtle: Low-Ratio Color Blending" }, description: { zh: "沃羅諾伊紋理（Voronoi Texture）的顏色（Color）輸出直接接到底色，每個細胞會是一塊隨機的鮮豔色塊——很搶眼，但很少有真實材質長這樣。這篇教鍍鋅浪板（Galvanized Zinc）這個材質用的技巧：不要直接顯示 Voronoi 的顏色，而是用混合顏色（Mix Color）把它以很低的比例（例如 0.22）疊回一個基底色，色塊立刻從「拼貼馬賽克」變成金屬表面本身那種若隱若現的結晶紋路。", en: "Wiring Voronoi Texture's Color output straight into a base color gives each cell a bold random flat color — striking, but few real materials actually look like that. This tutorial teaches the trick used in the Galvanized Zinc preset: instead of showing Voronoi's Color directly, blend it into a base tone at a low ratio (e.g. 0.22) using Mix Color. The cells instantly go from looking like a tiled mosaic to the subtle crystalline pattern a real metal surface has." }, level: { zh: "中階", en: "Intermediate" } },
];
